#include <bits/stdc++.h>
using namespace std;

const int N=47;

int n,w,g[N],val[(1<<23)+1],cnt,ans;

int main(){
    scanf("%d%d",&w,&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&g[i]);
    if(n==1){
        printf("%d",(g[1]<=w)*g[1]);
        return 0;
    }
    int a=n-n/2,b=n/2;
    for(int i=0;i<1<<a;i++){
        long long sum=0;
        for(int j=i;j;j-=(j&(-j))){
            int p=log2(j&(-j))+1;
            sum+=g[p];
            if(sum>w)
                break;
        }
        if(sum>w)
            continue;
        val[++cnt]=sum;
    }
    sort(val+1,val+cnt+1);
    for(int i=0;i<1<<b;i++){
        long long sum=0;
        for(int j=i;j;j-=(j&(-j))){
            int p=log2(j&(-j))+a+1;
            sum+=g[p];
            if(sum>w)
                break;
        }
        if(sum>w)
            continue;
        int l=1,r=cnt;
        while(l<r){
            int mid=l+r+1>>1;
            if(val[mid]+sum>w)
                r=mid-1;
            else
                l=mid;
        }
        ans=max(1ll*ans,val[l]+sum);
    }
    printf("%d",ans);
    return 0;
}
